import jsonclass ExpenseTracker:    def __init__(self):        self.expenses = []    def load_expenses(self):        try:            with open("expense.json", "r") as file:                self.expenses = json.load(file)                return self.expenses        except FileNotFoundError:            return []    def save_expenses(self):        with open("expense.json", "w") as file:            json.dump(self.expenses, file)    def add_expense(self):        expense_name = input("Enter expense name: ")        while True:            try:                expense_amount = float(input("Enter expense amount: "))                break            except ValueError:                print("please enter a valid number")        expense = {            "name": expense_name,            "amount": expense_amount        }        self.expenses.append(expense)        self.save_expenses()        print(f"{expense['name']} added successfully!")    def view_expense(self):        if len(self.expenses) == 0:            print("No expenses found")        else:         for expense in self.expenses:            print(f"Expense name - {expense['name']} Expense amount = {expense['amount']} ")    def get_total(self):        total = 0        for expense in self.expenses:            total = total + expense['amount']        return totalclass SavingsTracker(ExpenseTracker):    def __init__(self,savings_goal):        super().__init__()        self.savings_goal = savings_goal    def check_goal(self):        total_spent = self.get_total()        remaining = self.savings_goal - total_spent        if remaining > 0:            print(f"You need {remaining} to reach your goal")        else:            print("You have reached your goal")if __name__ == "__main__":  while True:    try:        user_input = int(input("Choose tracker1 or tracker2: "))        break    except ValueError:        print("Invalid number , please try again")  if user_input == 1:    tracker = ExpenseTracker()  else:       while True:             try:              goal = float(input("Enter your savings goal: R"))              tracker = SavingsTracker(goal)              break             except ValueError:                print("Invalid number , please try again")  tracker.load_expenses()  if user_input == 1:      while True:        print("1.Add expense")        print("2.View expense")        print("3.Get total")        print("4.Quit")        while True:            try:             menu_option = int(input("Please select a menu option: "))             break            except ValueError:                print("Invalid number, please try again")        if menu_option == 1:            tracker.add_expense()        elif menu_option == 2:            tracker.view_expense()        elif menu_option == 3:            print(f"total expenses: R{tracker.get_total()}")        elif menu_option == 4:            print("Goodbye")            break        else:            print("Invalid option , please try")  else:      while True:          print("1.Add expense")          print("2.View expense")          print("3.Get total")          print("4.Check savings goal")          print("5.Quit")          while True:              try:                  menu_option =int(input("Enter menu option: "))                  break              except ValueError:                  print("Invalid number, please try again")          if menu_option == 1:            tracker.add_expense()          elif menu_option == 2:              tracker.view_expense()          elif menu_option == 3:              print(f"Your total is R{tracker.get_total()}")          elif menu_option == 4:              tracker.check_goal()          elif menu_option == 5:              print("Goodbye!")              break